import { Link } from 'react-router-dom';

export default function Room(props) {
  return (
    <Link to={"/room/"+props.name}>
    <div style={{backgroundColor:props.color}}>
        <h1>{props.i.name}</h1>
    </div>
    </Link>
  )
}
